 27	import { isParentKiosk, kioskContextMenuAction } from 'components/Kiosk/KioskActions';
 28	import * as API from '../../../services/Api';
 29	import { PromisesRegistry } from 'utils/CancelablePromises';
 30	import { filterAutogeneratedGateways, getGatewaysAsList, PeerAuthentication } from 'types/IstioObjects';
 31	import { ServiceWizardActionsDropdownGroup } from 'components/IstioWizards/ServiceWizardActionsDropdownGroup';
 32	import { WizardAction, WizardMode } from 'components/IstioWizards/WizardActions';
 33	import { ServiceDetailsInfo } from 'types/ServiceInfo';
 34	import { kialiStyle } from 'styles/StyleUtils';
 35	import { DropdownGroup, DropdownItem } from '@patternfly/react-core';
 36	import { getGVKTypeString } from '../../../utils/IstioConfigUtils';
 37	import { gvkType } from '../../../types/IstioConfigList';
 38	
 39	const graphNavHandler = (node: GraphElement, kiosk: string): void => {
 40	  handleGraphNav(node, kiosk);
 41	};
