 50	    return Promise.resolve([]);
 51	  }
 52	
 53	  const options = getOptions(nodeData);
 54	
 55	  if (!(nodeData.isServiceEntry || (nodeData.nodeType === NodeType.BOX && nodeData.isBox !== BoxByType.APP))) {
 56	    options.unshift(
 57	      nodeData.isOutside
 58	        ? ({
 59	            text: 'Namespace Graph',
 60	            altClickHandler: graphNavHandler,
 61	            external: false,
 62	            node: node,
 63	            target: '',
 64	            url: ''
 65	          } as ContextMenuOption)
 66	        : ({
 67	            text: 'Node Graph',
 68	            altClickHandler: graphNavHandler,
 69	            external: false,
 70	            node: node,
 71	            target: '',
 72	            url: ''
 73	          } as ContextMenuOption)
 74	    );
 75	  }
 76	
 77	  const contextMenuStyle = kialiStyle({
 78	    paddingTop: 0,
 79	    paddingBottom: 0
 80	  });
 81	
 82	  const menuOptions = options.map((o, i) => {
 83	    return (
 84	      // TODO: fix kiosk param
 85	      !!o.altClickHandler ? (
 86	        <DropdownItem
 87	          className={contextMenuStyle}
 88	          key={`option-${i}`}
 89	          onClick={() => o.altClickHandler!(o.node!, kiosk)}
 90	        >
 91	          {o.text}
 92	        </DropdownItem>
 93	      ) : (
 94	        <DropdownItem className={contextMenuStyle} key={`option-${i}`} onClick={() => clickHandler(o, kiosk)}>
 95	          {o.text} {o.target === '_blank' && <ExternalLinkAltIcon />}
 96	        </DropdownItem>
 97	      )
 98	    );
 99	  });
100	
101	  if (menuOptions.length > 0) {
102	    items.push(<DropdownGroup key={`group_show`} label={'Show'} children={menuOptions} />);
103	  }
104	
105	  if (nodeData.nodeType !== NodeType.SERVICE) {
106	    // Add margin bottom if the service wizard is not added
107	    items.push(<div style={{ marginBottom: '0.5rem' }}></div>);
108	
109	    return Promise.resolve(items);
110	  }
111	
112	  const getDetailPromise = promises.register(
113	    'getDetailPromise',
114	    API.getServiceDetail(nodeData.namespace, nodeData.service!, false, nodeData.cluster)
115	  );
116	  const getGwPromise = promises.register(
117	    'getGwPromise',
118	    API.getAllIstioConfigs([getGVKTypeString(gvkType.Gateway)], false, '', '', nodeData.cluster)
119	  );
120	  const getPeerAuthsPromise = promises.register(
121	    'getPeerAuthsPromise',
122	    API.getIstioConfig(
123	      nodeData.namespace,
124	      [getGVKTypeString(gvkType.PeerAuthentication)],
125	      false,
126	      '',
127	      '',
128	      nodeData.cluster
129	    )
130	  );
131	
132	  return new Promise<React.ReactElement[]>((resolve, reject) => {
133	    Promise.all([getDetailPromise, getGwPromise, getPeerAuthsPromise])
134	      .then(results => {
135	        const serviceDetails = results[0];
136	        const gateways = getGatewaysAsList(
137	          filterAutogeneratedGateways(results[1].data.resources[getGVKTypeString(gvkType.Gateway)])
138	        ).sort();
139	        const peerAuthentications = results[2].data.resources[getGVKTypeString(gvkType.PeerAuthentication)];
140	
141	        items.push(
142	          <ServiceWizardActionsDropdownGroup
143	            className={contextMenuStyle}
144	            destinationRules={serviceDetails.destinationRules ?? []}
145	            istioPermissions={serviceDetails.istioPermissions}
146	            k8sHTTPRoutes={serviceDetails.k8sHTTPRoutes ?? []}
147	            k8sGRPCRoutes={serviceDetails.k8sGRPCRoutes ?? []}
148	            onAction={(key: WizardAction, mode: WizardMode): void =>
149	              handleLaunchWizard(key, mode, node, serviceDetails, gateways, peerAuthentications)
150	            }
151	            onDelete={(key): void => handleDeleteTrafficRouting(key, node, serviceDetails)}
152	            virtualServices={serviceDetails.virtualServices ?? []}
153	          />
154	        );
155	        resolve(items);
156	      })
157	      .catch(error => {
158	        if (error.isCanceled) {
159	          return;
160	        }
161	        reject(error);
162	      });
163	  });
164	};
165	
166	const handleLaunchWizard = (
167	  key: WizardAction,
168	  mode: WizardMode,
169	  node: GraphElement,
170	  serviceDetails: ServiceDetailsInfo,
171	  gateways: string[],
172	  peerAuthentications: PeerAuthentication[]
173	): void => {
174	  node
175	    .getGraph()
176	    .getData()
177	    .onLaunchWizard(key, mode, node.getData().namespace, serviceDetails, gateways, peerAuthentications);
178	};
179	
180	const handleDeleteTrafficRouting = (key: string, node: GraphElement, serviceDetails: ServiceDetailsInfo): void => {
181	  node.getGraph().getData().onDeleteTrafficRouting(key, serviceDetails);
182	};
183	
184	const handleGraphNav = (fromNode: GraphElement, kiosk: string): void => {
185	  const fromNodeData = fromNode.getData() as DecoratedGraphNodeData;
186	  const graphData = fromNode.getGraph().getData().graphData;
187	
188	  if (
189	    fromNodeData.isInaccessible ||
190	    fromNodeData.isServiceEntry ||
191	    (fromNodeData.nodeType === NodeType.BOX && fromNodeData.isBox !== BoxByType.APP)
192	  ) {
193	    return;
194	  }
195	
196	  if (fromNodeData.isOutOfMesh) {
197	    if (!serverConfig.ambientEnabled) {
198	      AlertUtils.add(
199	        `A node with a missing sidecar provides no node-specific telemetry and can not provide a node detail graph.`,
200	        undefined,
201	        MessageType.WARNING
202	      );
203	    } else {
204	      AlertUtils.add(
205	        `A node out of the mesh provides no node-specific telemetry and can not provide a node detail graph.`,
206	        undefined,
207	        MessageType.WARNING
208	      );
209	    }
210	
211	    return;
212	  }
213	  if (fromNodeData.isIdle) {
214	    AlertUtils.add(
215	      `An idle node has no node-specific traffic and can not provide a node detail graph.`,
216	      undefined,
217	      MessageType.WARNING
218	    );
219	    return;
220	  }
221	  if (fromNodeData.isOutside) {
222	    store.dispatch(NamespaceActions.setActiveNamespaces([{ name: fromNodeData.namespace }]));
223	    return;
224	  }
225	
226	  // If graph is in the drilled-down view, there is the chance that the user
227	  // selected the same node as in the full graph. Determine if this is the case.
228	  // note = this may not be a concern in PF graph, but I'm not sure...
229	  let sameNode = false;
230	  const node = graphData.fetchParams.node;
231	  if (node) {
232	    sameNode = node && node.nodeType === fromNodeData.nodeType;
233	    switch (fromNodeData.nodeType) {
234	      case NodeType.AGGREGATE:
235	        sameNode = sameNode && node.aggregate === fromNodeData.aggregate;
236	        sameNode = sameNode && node.aggregateValue === fromNodeData.aggregateValue;
237	        break;
238	      case NodeType.APP:
239	        sameNode = sameNode && node.app === fromNodeData.app;
240	        sameNode = sameNode && node.version === fromNodeData.version;
241	        break;
242	      case NodeType.BOX:
243	        // we only support node graphs on app boxes, so assume app box
244	        sameNode = sameNode && node.app === fromNodeData.app;
245	        break;
246	      case NodeType.SERVICE:
247	        sameNode = sameNode && node.service === fromNodeData.service;
248	        break;
249	      case NodeType.WORKLOAD:
250	        sameNode = sameNode && node.workload === fromNodeData.workload;
251	        break;
252	      default:
253	        sameNode = true; // don't navigate to unsupported node type
254	    }
255	  }
256	
257	  const { app, cluster, namespace, nodeType, service, version, workload } = fromNodeData;
258	  const event = { app, cluster, namespace, nodeType, service, version, workload } as any;
259	  const targetNode: NodeParamsType = { ...event, namespace: { name: fromNodeData.namespace } };
260	
261	  // If, while in the drilled-down graph, the user selected the same
262	  // node as in the main graph, it doesn't make sense to re-load the same view.
263	  // Instead, assume that the user wants more details for the node and do a
264	  // redirect to the details page.
265	  if (sameNode) {
266	    handleSameNode(targetNode, kiosk);
267	    return;
268	  }
269	
270	  // In case user didn't select the same node, or if graph is in
271	  // full graph mode, redirect to the drilled-down graph of the chosen node.
272	  const state = store.getState();
273	  const urlParams: GraphUrlParams = {
274	    activeNamespaces: graphData.fetchParams.namespaces,
275	    duration: graphData.fetchParams.duration,
276	    edgeLabels: graphData.fetchParams.edgeLabels,
277	    edgeMode: state.graph.edgeMode,
278	    graphLayout: state.graph.layout,
279	    graphType: graphData.fetchParams.graphType,
280	    namespaceLayout: state.graph.namespaceLayout,
281	    node: targetNode,
282	    refreshInterval: state.userSettings.refreshInterval,
283	    showIdleEdges: state.graph.toolbarState.showIdleEdges,
284	    showIdleNodes: state.graph.toolbarState.showIdleNodes,
285	    showOperationNodes: state.graph.toolbarState.showOperationNodes,
286	    showServiceNodes: state.graph.toolbarState.showServiceNodes,
287	    showVirtualServices: state.graph.toolbarState.showVirtualServices,
288	    showWaypoints: state.graph.toolbarState.showWaypoints,
289	    trafficRates: graphData.fetchParams.trafficRates
290	  };
291	
292	  // To ensure updated components get the updated URL, update the URL first and then the state
293	  const nodeGraphUrl = makeNodeGraphUrlFromParams(urlParams);
294	
295	  if (isParentKiosk(kiosk)) {
296	    kioskContextMenuAction(nodeGraphUrl);
297	  } else {
298	    router.navigate(nodeGraphUrl);
299	  }
300	};
301	
302	// This allows us to navigate to the service details page when zoomed in on nodes
303	const handleSameNode = (targetNode: NodeParamsType, kiosk: string): void => {
304	  const makeAppDetailsPageUrl = (namespace: string, nodeType: string, name?: string): string => {
305	    return `/namespaces/${namespace}/${nodeType}/${name}`;
306	  };
307	  const nodeType = targetNode.nodeType;
308	  let urlNodeType = `${targetNode.nodeType}s`;
309	  let name = targetNode.app;
310	
311	  if (nodeType === 'service') {
312	    name = targetNode.service;
313	  } else if (nodeType === 'workload') {
314	    name = targetNode.workload;
315	  } else {
316	    urlNodeType = 'applications';
317	  }
318	
319	  let detailsPageUrl = makeAppDetailsPageUrl(targetNode.namespace.name, urlNodeType, name);
320	
321	  if (targetNode.cluster && isMultiCluster) {
322	    detailsPageUrl = `${detailsPageUrl}?clusterName=${targetNode.cluster}`;
323	  }
324	
325	  if (isParentKiosk(kiosk)) {
326	    kioskContextMenuAction(detailsPageUrl);
327	  } else {
328	    router.navigate(detailsPageUrl);
329	  }
330	};
331	
332	export const stylesComponentFactory: ComponentFactory = (
333	  kind: ModelKind,
334	  type: string
335	): React.FunctionComponent<any> | undefined => {
336	  const kiosk = store.getState().globalState.kiosk;
337	
338	  switch (kind) {
339	    case ModelKind.edge:
340	      return withSelection({ multiSelect: false, controlled: false })(StyleEdge as any);
341	    case ModelKind.graph:
342	      return withSelection({ multiSelect: false, controlled: false })(
343	        withPanZoom()(withAreaSelection(['ctrlKey', 'shiftKey'])(GraphComponent))
344	      );
345	    case ModelKind.node: {
346	      return withDragNode(nodeDragSourceSpec('node', true, true))(
347	        withContextMenu(e => nodeContextMenu(e, kiosk))(
348	          withSelection({ multiSelect: false, controlled: false })((type === 'group' ? StyleGroup : StyleNode) as any)
349	        )
350	      );
351	    }
352	    default:
353	      return undefined;
354	  }
355	};

