257	  const { app, cluster, namespace, nodeType, service, version, workload } = fromNodeData;
258	  const event = { app, cluster, namespace, nodeType, service, version, workload } as any;
259	  const targetNode: NodeParamsType = { ...event, namespace: { name: fromNodeData.namespace } };
260	
261	  // If, while in the drilled-down graph, the user selected the same
262	  // node as in the main graph, it doesn't make sense to re-load the same view.
263	  // Instead, assume that the user wants more details for the node and do a
264	  // redirect to the details page.
265	  if (sameNode) {
266	    handleSameNode(targetNode, kiosk);
267	    return;
268	  }
269	
270	  // In case user didn't select the same node, or if graph is in
271	  // full graph mode, redirect to the drilled-down graph of the chosen node.
272	  const state = store.getState();
273	  const urlParams: GraphUrlParams = {
274	    activeNamespaces: graphData.fetchParams.namespaces,
275	    duration: graphData.fetchParams.duration,
276	    edgeLabels: graphData.fetchParams.edgeLabels,
277	    edgeMode: state.graph.edgeMode,
278	    graphLayout: state.graph.layout,
279	    graphType: graphData.fetchParams.graphType,
280	    namespaceLayout: state.graph.namespaceLayout,
281	    node: targetNode,
282	    refreshInterval: state.userSettings.refreshInterval,
283	    showIdleEdges: state.graph.toolbarState.showIdleEdges,
284	    showIdleNodes: state.graph.toolbarState.showIdleNodes,
285	    showOperationNodes: state.graph.toolbarState.showOperationNodes,
286	    showServiceNodes: state.graph.toolbarState.showServiceNodes,
287	    showVirtualServices: state.graph.toolbarState.showVirtualServices,
288	    showWaypoints: state.graph.toolbarState.showWaypoints,
289	    trafficRates: graphData.fetchParams.trafficRates
290	  };
291	
292	  // To ensure updated components get the updated URL, update the URL first and then the state
293	  const nodeGraphUrl = makeNodeGraphUrlFromParams(urlParams);
294	
295	  if (isParentKiosk(kiosk)) {
296	    kioskContextMenuAction(nodeGraphUrl);
297	  } else {
298	    router.navigate(nodeGraphUrl);
299	  }
300	};
301	
302	// This allows us to navigate to the service details page when zoomed in on nodes
303	const handleSameNode = (targetNode: NodeParamsType, kiosk: string): void => {
304	  const makeAppDetailsPageUrl = (namespace: string, nodeType: string, name?: string): string => {
305	    return `/namespaces/${namespace}/${nodeType}/${name}`;
306	  };
307	  const nodeType = targetNode.nodeType;
308	  let urlNodeType = `${targetNode.nodeType}s`;
309	  let name = targetNode.app;
310	
311	  if (nodeType === 'service') {
312	    name = targetNode.service;
313	  } else if (nodeType === 'workload') {
314	    name = targetNode.workload;
315	  } else {
316	    urlNodeType = 'applications';
317	  }
318	
319	  let detailsPageUrl = makeAppDetailsPageUrl(targetNode.namespace.name, urlNodeType, name);
320	
321	  if (targetNode.cluster && isMultiCluster) {
322	    detailsPageUrl = `${detailsPageUrl}?clusterName=${targetNode.cluster}`;
323	  }
324	
325	  if (isParentKiosk(kiosk)) {
326	    kioskContextMenuAction(detailsPageUrl);
327	  } else {
328	    router.navigate(detailsPageUrl);
329	  }
330	};
331	
332	export const stylesComponentFactory: ComponentFactory = (
333	  kind: ModelKind,
334	  type: string
335	): React.FunctionComponent<any> | undefined => {
336	  const kiosk = store.getState().globalState.kiosk;
337	
338	  switch (kind) {
339	    case ModelKind.edge:
340	      return withSelection({ multiSelect: false, controlled: false })(StyleEdge as any);
341	    case ModelKind.graph:
342	      return withSelection({ multiSelect: false, controlled: false })(
343	        withPanZoom()(withAreaSelection(['ctrlKey', 'shiftKey'])(GraphComponent))
344	      );
345	    case ModelKind.node: {
346	      return withDragNode(nodeDragSourceSpec('node', true, true))(
347	        withContextMenu(e => nodeContextMenu(e, kiosk))(
348	          withSelection({ multiSelect: false, controlled: false })((type === 'group' ? StyleGroup : StyleNode) as any)
349	        )
350	      );
351	    }
352	    default:
353	      return undefined;
354	  }
355	};

